// Glues CsrTrigger and StateDrain. The simulator's run-loop calls on_retire
// once per committed PC; the controller decides via the trigger map whether
// to drain state and returns the populated hybrid_state_v1 if so. The
// caller (simulator.hpp) is responsible for writing the file and exiting
// with EXIT_HANDOFF_TO_QEMU.

#pragma once

#include "hybrid/csr_trigger.hpp"
#include "hybrid/insn_match.h"
#include "hybrid/resume_driver.hpp"
#include "hybrid/state_abi.h"
#include "hybrid/state_drain.hpp"

#include <cstdint>
#include <optional>
#include <utility>

namespace hybrid
{

class HandoffController
{
public:
  HandoffController(CsrTrigger trigger, DmiBus& bus)
      : trigger_{std::move(trigger)}, drain_{bus}
  {}

  // Snapshot of the QEMU 1 input state. When set, drain merges FP/CSR/V
  // fields from the snapshot into the freshly drained GPRs+PC, avoiding
  // a per-field DM Abstract Command on every handoff.
  void set_passthrough_input(hybrid_state_v1 input)
  {
    passthrough_ = input;
  }

  template<typename GprProbe>
  auto on_retire(uint64_t pc, GprProbe&& read_gpr)
    -> std::optional<hybrid_state_v1>
  {
    const auto hit = trigger_.lookup(pc);
    if (!hit) return std::nullopt;

    bool fire = false;
    switch (hit->kind) {
    case HYBRID_HANDOFF_EXIT:
      fire = true;
      break;
    case HYBRID_HANDOFF_RUNTIME: {
      const auto rs1 = decode_csrrw_rs1(hit->insn);
      fire = (read_gpr(rs1) == 1u);
      break;
    }
    case HYBRID_HANDOFF_ENTER:  // entry is QEMU's job; vsim ignores it
    case HYBRID_HANDOFF_NONE:
      break;
    }
    if (!fire) return std::nullopt;
    if (passthrough_) return drain_.drain_with_passthrough(*passthrough_);
    return drain_.drain();
  }

private:
  CsrTrigger trigger_;
  StateDrain drain_;
  std::optional<hybrid_state_v1> passthrough_;
};

}  // namespace hybrid

