35	namespace hybrid
36	{
37	
38	namespace detail
39	{
40	
41	inline auto pick_free_port() -> uint16_t
42	{
43	  const int s = ::socket(AF_INET, SOCK_STREAM, 0);
44	  if (s < 0)
45	    throw std::runtime_error("pick_free_port: socket");
46	
47	  sockaddr_in addr{};
48	  addr.sin_family      = AF_INET;
49	  addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
50	  addr.sin_port        = 0;
51	
52	  if (::bind(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) < 0) {
53	    ::close(s);
54	    throw std::runtime_error("pick_free_port: bind");
55	  }
56	  socklen_t len = sizeof(addr);
57	  if (::getsockname(s, reinterpret_cast<sockaddr*>(&addr), &len) < 0) {
58	    ::close(s);
59	    throw std::runtime_error("pick_free_port: getsockname");
60	  }
61	  ::close(s);
62	  return ntohs(addr.sin_port);
63	}
64	
65	// Thrown by connect_loopback when the watched child exits before the
66	// gdbstub becomes reachable (typically: bad --qemu-binary path).
67	struct ChildExitedDuringConnect
68	{
69	  int status;
70	};
71	
72	inline auto connect_loopback(uint16_t port,
73	                             std::chrono::milliseconds timeout,
74	                             pid_t child_pid = -1) -> int
75	{
76	  const auto deadline = std::chrono::steady_clock::now() + timeout;
77	  while (std::chrono::steady_clock::now() < deadline) {
78	    const int s = ::socket(AF_INET, SOCK_STREAM, 0);
79	    if (s < 0)
80	      throw std::runtime_error("connect_loopback: socket");
81	    sockaddr_in addr{};
82	    addr.sin_family      = AF_INET;
83	    addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
84	    addr.sin_port        = htons(port);
85	    if (::connect(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) == 0)
86	      return s;
87	    ::close(s);
88	    if (child_pid > 0) {
89	      int wstat = 0;
90	      if (::waitpid(child_pid, &wstat, WNOHANG) == child_pid) {
91	        int status = -1;
92	        if (WIFEXITED(wstat)) status = WEXITSTATUS(wstat);
93	        else if (WIFSIGNALED(wstat)) status = 128 + WTERMSIG(wstat);
94	        throw ChildExitedDuringConnect{status};
95	      }
96	    }
97	    std::this_thread::sleep_for(std::chrono::milliseconds(20));
98	  }
99	  throw std::runtime_error("connect_loopback: timed out waiting for QEMU "
100	                           "gdbstub");
101	}
102	
103	inline auto spawn_qemu(const std::string& binary,
104	                       const std::string& elf,
105	                       uint16_t gdb_port,
106	                       const std::string& shared_mem_path = {},
107	                       uint64_t shared_mem_size = 0) -> pid_t
108	{
109	  const pid_t pid = ::fork();
110	  if (pid < 0)
111	    throw std::runtime_error(std::string{"spawn_qemu: fork: "}
112	                             + std::strerror(errno));
113	  if (pid == 0) {
114	    // Detach the child from the caller's tty. -nographic makes QEMU's
115	    // chardev backend tcsetattr() stdin into raw mode; if the caller is
116	    // launched from a non-foreground process group (e.g. under timeout(1)),
117	    // that touch raises SIGTTOU/SIGTTIN and stops QEMU 2, hanging vsim's
118	    // waitpid. /dev/null sidesteps the tty entirely.
119	    const int devnull = ::open("/dev/null", O_RDONLY | O_CLOEXEC);
120	    if (devnull >= 0) {
121	      ::dup2(devnull, STDIN_FILENO);
122	      ::close(devnull);
123	    }
124	
125	    const std::string gdb_arg = "tcp::" + std::to_string(gdb_port);
126	    const std::string mem_obj = "memory-backend-file,id=mem,share=on,mem-path="
127	                              + shared_mem_path
128	                              + ",size=" + std::to_string(shared_mem_size);
129	    std::vector<const char*> argv;
130	    argv.push_back(binary.c_str());
131	    if (!shared_mem_path.empty()) {
132	      argv.push_back("-object");
133	      argv.push_back(mem_obj.c_str());
134	      argv.push_back("-machine");
135	      argv.push_back("andes_ae350,memory-backend=mem");
136	    } else {
137	      argv.push_back("-M");
138	      argv.push_back("virt");
139	    }
140	    // -cpu andes-ax45mpv,vlen=512: matches QEMU 1's CPU and the vsim RTL
141	    // build (NDS_VLEN 512). Without this, QEMU 2 defaults to plain rv64
142	    // (no V), mstatus.VS becomes read-only zero, and vsetvli traps with
143	    // illegal-instruction as soon as a V-using fixture's Phase 3 runs.
144	    // Andes vendor CSRs touched by the runtime crt0 (mcache_ctl, mmisc_ctl,
145	    // ...) are also gated here.
146	    argv.push_back("-cpu");
147	    argv.push_back("andes-ax45mpv,vlen=512");
148	    argv.push_back("-bios");
149	    argv.push_back("none");
150	    argv.push_back("-nographic");
151	    argv.push_back("-semihosting-config");
152	    argv.push_back("enable=on,target=native");
153	    // In tier-2 (shared mmap), .text/.rodata/.data are already in the
154	    // shared file from QEMU 1's -kernel; re-loading here would zero
155	    // .bss and reset .data, destroying memory written in phase 2. The
156	    // resume PC is restored via gdbstub P32 below, so the ELF entry
157	    // point is irrelevant. Tier-1 (no shared mmap) still needs -kernel
158	    // to populate QEMU 2's private RAM.
159	    if (shared_mem_path.empty()) {
160	      argv.push_back("-kernel");
161	      argv.push_back(elf.c_str());
162	    }
163	    argv.push_back("-gdb");
164	    argv.push_back(gdb_arg.c_str());
165	    argv.push_back("-S");
166	    argv.push_back(nullptr);
167	
168	    ::execv(binary.c_str(), const_cast<char* const*>(argv.data()));
169	    std::fprintf(stderr, "exec %s: %s\n", binary.c_str(),
170	                 std::strerror(errno));
171	    ::_exit(127);
172	  }
173	  return pid;
174	}
175	
176	}  // namespace detail
177	
178	namespace detail
179	{
180	
181	// Fetches a qXfer:features:read annex in full, looping while the stub
182	// answers with the 'm' (more) marker. QEMU's RISC-V CSR XML is ~6 KB and
183	// PacketSize is typically 1000 bytes, so several iterations are normal.
184	inline auto fetch_feature_xml(gdbstub::Session& sess, const std::string& annex)
185	  -> std::string
186	{
187	  std::string accum;
188	  std::size_t offset = 0;
189	  // Use a chunk size below the QEMU default PacketSize=1000. Asking for
190	  // 0x100 keeps each frame well under the wire limit even after the 'm'
191	  // marker and packet framing overhead.
192	  constexpr std::size_t kChunk = 0x100;
193	  while (true) {
194	    char buf[64];
195	    std::snprintf(buf, sizeof(buf), ":%zx,%zx", offset, kChunk);
196	    auto body = sess.send_command("qXfer:features:read:" + annex + buf);
197	    if (body.empty())
198	      throw std::runtime_error("qXfer empty reply for " + annex);
199	    const char marker = body.front();
200	    if (marker != 'l' && marker != 'm')
201	      throw std::runtime_error("qXfer non-l/m reply for " + annex + ": "
202	                               + std::string{marker});
203	    accum.append(body.substr(1));
204	    if (marker == 'l') return accum;
205	    offset += body.size() - 1;
206	  }
207	}
208	
209	// Walks target.xml and every <xi:include> annex, returning the merged
210	// register-name -> packet-number map.
211	inline auto discover_reg_map(gdbstub::Session& sess) -> gdbstub::RegMap
212	{
213	  gdbstub::RegMap map;
214	  const auto target_xml = fetch_feature_xml(sess, "target.xml");
215	  unsigned next = 0;
216	  for (const auto& annex : gdbstub::parse_target_xml(target_xml)) {
217	    const auto annex_xml = fetch_feature_xml(sess, annex);
218	    gdbstub::parse_feature_xml(annex_xml, map, next);
219	  }
220	  return map;
221	}
222	
223	// Sends one P packet whose body is built by the supplied encoder. A
224	// missing register name is silently skipped: not every QEMU build
225	// advertises every PMP slot or extension CSR, so absence isn't fatal.
226	template<class Session, class Encoder>
227	inline void try_write_named(Session& sess,
228	                            const gdbstub::RegMap& map,
229	                            const std::string& name,
230	                            Encoder&& encoder)
231	{
232	  const auto reg_num = map.find(name);
233	  if (!reg_num) return;
234	  auto reply = sess.send_command(encoder(*reg_num));
235	  if (reply != "OK")
236	    throw std::runtime_error("gdbstub: P packet for " + name + " replied "
237	                             + reply);
238	}
239	
240	template<class Session>
241	inline void try_write_named_u64(Session& sess,
242	                                const gdbstub::RegMap& map,
243	                                const std::string& name,
244	                                uint64_t value)
245	{
246	  try_write_named(sess, map, name, [&](unsigned r) {
247	    return gdbstub::encode_p_body(r, value);
248	  });
249	}
250	
251	template<class Session>
252	inline void try_write_named_bytes(Session& sess,
253	                                  const gdbstub::RegMap& map,
254	                                  const std::string& name,
255	                                  const uint8_t* bytes,
256	                                  std::size_t n)
257	{
258	  try_write_named(sess, map, name, [&](unsigned r) {
259	    return gdbstub::encode_p_body_bytes(r, bytes, n);
260	  });
261	}
262	
263	// FP register names match the riscv-64bit-fpu.xml feature; the table
264	// itself is shared with the QEMU plugin via hybrid/reg_names.h.
265	
266	inline constexpr std::array<std::pair<const char*, uint64_t hybrid_state_v1::*>,
267	                            13>
268	  kCsrByName = {{
269	    {"mstatus",  &hybrid_state_v1::mstatus},
270	    {"mepc",     &hybrid_state_v1::mepc},
271	    {"mtvec",    &hybrid_state_v1::mtvec},
272	    {"mcause",   &hybrid_state_v1::mcause},
273	    {"mtval",    &hybrid_state_v1::mtval},
274	    {"mscratch", &hybrid_state_v1::mscratch},
275	    {"medeleg",  &hybrid_state_v1::medeleg},
276	    {"mideleg",  &hybrid_state_v1::mideleg},
277	    {"mip",      &hybrid_state_v1::mip},
278	    {"mie",      &hybrid_state_v1::mie},
279	    {"mcycle",   &hybrid_state_v1::mcycle},
280	    {"minstret", &hybrid_state_v1::minstret},
281	    {"satp",     &hybrid_state_v1::satp},
282	  }};
283	
284	// apply_state writes all architectural state fields to the gdbstub session.
285	// Templated on Session so tests can inject a recording stub without a real
286	// TCP socket (duck-type: needs send_command(string_view)->string).
287	template<class Session>
288	inline void apply_state(Session& sess,
289	                        const gdbstub::RegMap& reg_map,
290	                        const hybrid_state_v1& state)
291	{
292	  // RV64 core: x0..x31 = 0..31, pc = 32. Hard-coded because the core
293	  // feature is always first.
294	  for (unsigned i = 1; i < 32; ++i) {
295	    auto reply = sess.send_command(gdbstub::encode_p_body(i, state.gpr[i]));
296	    if (reply != "OK")
297	      throw std::runtime_error(
298	        "gdbstub: P packet for x" + std::to_string(i) + " replied " + reply);
299	  }
300	  auto reply = sess.send_command(gdbstub::encode_p_body(32, state.pc));
301	  if (reply != "OK")
302	    throw std::runtime_error("gdbstub: P32 (pc) replied " + reply);
303	
304	  if ((state.flags & HYBRID_FLAG_FP) != 0u)
305	    for (std::size_t i = 0; i < 32; ++i)
306	      try_write_named_u64(sess, reg_map, hybrid_fpr_names[i], state.fpr[i]);
307	
308	  for (const auto& slot : kCsrByName)
309	    try_write_named_u64(sess, reg_map, slot.first, state.*(slot.second));
310	
311	  for (uint16_t i = 0; i < HYBRID_PMP_CFG_NUM; ++i)
312	    try_write_named_u64(sess, reg_map, "pmpcfg" + std::to_string(i),
313	                        state.pmpcfg[i]);
314	  for (uint16_t i = 0; i < HYBRID_PMP_ADDR_NUM; ++i)
315	    try_write_named_u64(sess, reg_map, "pmpaddr" + std::to_string(i),
316	                        state.pmpaddr[i]);
317	
318	  if ((state.flags & HYBRID_FLAG_V) != 0u && state.vlenb > 0u
319	      && state.vlenb <= HYBRID_VLEN_BYTES_MAX) {
320	    try_write_named_u64(sess, reg_map, "vstart", state.vstart);
321	    try_write_named_u64(sess, reg_map, "vxsat",  state.vxsat);
322	    try_write_named_u64(sess, reg_map, "vxrm",   state.vxrm);
323	    try_write_named_u64(sess, reg_map, "vcsr",   state.vcsr);
324	    try_write_named_u64(sess, reg_map, "vtype",  state.vtype);
325	    try_write_named_u64(sess, reg_map, "vl",     state.vl);
326	    const std::size_t vbytes = static_cast<std::size_t>(state.vlenb);
327	    for (uint16_t i = 0; i < 32; ++i) {
328	      const std::string name = "v" + std::to_string(i);
329	      try_write_named_bytes(
330	        sess, reg_map, name,
331	        &state.vreg[static_cast<std::size_t>(i) * HYBRID_VLEN_BYTES_MAX],
332	        vbytes);
333	    }
334	  }
335	}
336	
337	}  // namespace detail
338	
339	// Restores x1..x31, PC, FPR (if HYBRID_FLAG_FP), M-mode CSRs, PMP, and
340	// vector data regs (if HYBRID_FLAG_V) into the QEMU vCPU via the gdbstub
341	// at `port`, then continues. Caller is responsible for waitpid().
342	inline void restore_state_via_gdbstub(uint16_t port,
343	                                      const hybrid_state_v1& state,
344	                                      pid_t child_pid = -1)
345	{
346	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
347	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5),
348	                                          child_pid);
349	  spdlog::info("hybrid handback: connected, discovering register map");
350	  gdbstub::Session sess{fd};
351	
352	  const auto reg_map = detail::discover_reg_map(sess);
353	  spdlog::info("hybrid handback: {} registers advertised, restoring state",
354	               reg_map.size());
355	
356	  detail::apply_state(sess, reg_map, state);
357	
358	  spdlog::info("hybrid handback: continuing target");
359	  sess.cont();
360	}
